export async function seedShodan() {
    try {
        console.log("Seeding tool Shodan...");
        await Tool.deleteMany({ name: "Shodan" });
        
        const toolDoc = new Tool(toolPayload);
        await toolDoc.save();
        
        console.log("Seeded tool Shodan successfully.");
    } catch (error) {
        console.error("Seeding tool Shodan failed:", error);
        throw error;
    }
}
